const response = $input.first().json;
const clientData = $('Generate Agreement Webhook').first().json.body || {};

// Documentero returns a URL to the generated PDF
const pdfUrl = response.data || response.url || response.document_url || '';

return [{
  json: {
    pdfUrl,
    clientEmail: clientData.email || '',
    clientName: clientData.fullName || clientData.name || '',
    entityName: clientData.entityName || '',
    tier: clientData.tier || 'Starter',
    generatedAt: new Date().toISOString()
  }
}];
